),
installations AS (
  SELECT DISTINCT
    "user_pseudo_id",
    MIN("user_first_touch_timestamp") AS first_touch_ts
  FROM all_events
  WHERE TO_DATE(TO_TIMESTAMP("user_first_touch_timestamp" / 1000000)) BETWEEN '2018-08-01' AND '2018-09-30'
  GROUP BY "user_pseudo_id"
),
uninstall_events AS (
  SELECT
    "user_pseudo_id",
    MIN("event_timestamp") AS uninstall_ts
  FROM all_events
  WHERE "event_name" = 'app_remove'
  GROUP BY "user_pseudo_id"
),
user_uninstall_check AS (
  SELECT
    i."user_pseudo_id",
    i.first_touch_ts,
    u.uninstall_ts,
    CASE
      WHEN u.uninstall_ts IS NULL THEN 1
      WHEN TO_TIMESTAMP(u.uninstall_ts / 1000000) > DATEADD(day, 7, TO_TIMESTAMP(i.first_touch_ts / 1000000)) THEN 1
      ELSE 0
    END AS not_uninstall_within_7
  FROM installations i
  LEFT JOIN uninstall_events u ON i."user_pseudo_id" = u."user_pseudo_id"
)
SELECT
  COUNT(*) AS total_installations,
  SUM(not_uninstall_within_7) AS not_uninstalled_within_7_count,
  100.0 * SUM(not_uninstall_within_7) / COUNT(*) AS percentage
FROM user_uninstall_check